// scoredata.org 오늘 경기 URL 생성 + 카테고리/말투 랜덤 선택
const today = new Date().toISOString().split('T')[0];

// 카테고리 랜덤 (1~7)
const category = Math.floor(Math.random() * 7) + 1;

// 말투 스타일
const TONE_STYLES = [
  { name: '형', guide: '반말 사용, 친근하고 확신에 찬 말투. "야 이거 봐", "이거 무조건이야", "형이 알려줄게" 스타일.', examples: ['야 이거 봐 진짜 미쳤어', '이거 무조건이야 내가 장담해', '형이 알려줄게 잘 들어'] },
  { name: '빡침', guide: '반말 사용, 답답하고 빡친 말투. "아 진짜 제발 데이터 좀 보고 찍어", "이걸 왜 몰라?" 스타일.', examples: ['아 진짜 제발 데이터 좀 보고 찍어', '이걸 왜 몰라 진짜 답답해', '아니 이게 말이 되냐고'] },
  { name: 'ASMR', guide: '존댓말 사용, 차분하고 전문적인 말투. "심상치 않습니다", "주목해야 할 부분이 있습니다" 스타일.', examples: ['여러분 이건 심상치 않습니다', '주목해야 할 부분이 있습니다', '데이터가 말해주고 있습니다'] }
];
const selectedTone = TONE_STYLES[Math.floor(Math.random() * TONE_STYLES.length)];

// scoredata.org에서 3개 스포츠 순차 조회를 위한 URL
// (오늘 경기 조회 노드에서 호출)
const scoredataUrl = `https://scoredata.org/api/scores/date?date=${today}`;

return [{
  json: {
    apiType: 'scoredata',
    today,
    category,
    toneStyle: selectedTone.name,
    toneGuide: selectedTone.guide,
    toneExamples: selectedTone.examples,
    fdoKey: 'e0397df419be4d21b4133e75af030ba6',
    scoredataUrl
  }
}];

// scoredata.org /api/scores/live 응답 → 주요 리그 필터 → 랜덤 선택 → 경기 목록 출력
const sportInput = $('종목 결정').first().json;
const raw = $input.first().json;
const today = sportInput.today;

/**
 * 주요 리그 매칭 (이름 태그 기반)
 */
const LEAGUE_PATTERNS = [
  { pattern: '[ENG D1]',  sport: 'soccer', name: 'Premier League', espnLeague: 'eng.1', fdoCode: 'PL', oddsSport: 'soccer_epl' },
  { pattern: '[SPA D1]',  sport: 'soccer', name: 'La Liga', espnLeague: 'esp.1', fdoCode: 'PD', oddsSport: 'soccer_spain_la_liga' },
  { pattern: '[ITA D1]',  sport: 'soccer', name: 'Serie A', espnLeague: 'ita.1', fdoCode: 'SA', oddsSport: 'soccer_italy_serie_a' },
  { pattern: '[GER D1]',  sport: 'soccer', name: 'Bundesliga', espnLeague: 'ger.1', fdoCode: 'BL1', oddsSport: 'soccer_germany_bundesliga' },
  { pattern: '[FRA D1]',  sport: 'soccer', name: 'Ligue 1', espnLeague: 'fra.1', fdoCode: 'FL1', oddsSport: 'soccer_france_ligue_one' },
  { pattern: '[KOR D1]',  sport: 'soccer', name: 'K League 1', espnLeague: null, fdoCode: '', oddsSport: 'soccer_korea_kleague1' },
  { pattern: 'NBA',       sport: 'basketball', name: 'NBA', espnLeague: 'nba', fdoCode: '', oddsSport: 'basketball_nba', exact: true },
  { pattern: 'MLB',       sport: 'baseball', name: 'MLB', espnLeague: 'mlb', fdoCode: '', oddsSport: 'baseball_mlb' },
  { pattern: 'KBO',       sport: 'baseball', name: 'KBO', espnLeague: null, fdoCode: '', oddsSport: 'baseball_mlb', exact: true },
];

function matchLeague(leagueName, pat) {
  if (pat.exact) return leagueName === pat.pattern || leagueName.startsWith(pat.pattern + ' ');
  return leagueName.includes(pat.pattern);
}

// /api/scores/live → { sports: { football: { matches: [...] }, basketball: { ... } } }
const sportsData = raw.sports || {};
const availableLeagues = [];

for (const [sportKey, sportObj] of Object.entries(sportsData)) {
  const matches = sportObj.matches || [];
  const byLeague = {};
  for (const m of matches) {
    const lid = m.league?.id;
    if (!lid) continue;
    if (!byLeague[lid]) byLeague[lid] = { league: m.league, matches: [] };
    byLeague[lid].matches.push(m);
  }

  for (const [lid, group] of Object.entries(byLeague)) {
    const leagueName = group.league.name || '';
    for (const pat of LEAGUE_PATTERNS) {
      if (matchLeague(leagueName, pat)) {
        const existing = availableLeagues.find(l => l.name === pat.name);
        if (existing) {
          existing.matches = existing.matches.concat(group.matches);
          existing.matchCount += group.matches.length;
        } else {
          availableLeagues.push({
            scoredataLeagueId: Number(lid),
            ...pat,
            leagueName,
            matchCount: group.matches.length,
            matches: group.matches
          });
        }
        break;
      }
    }
  }
}

if (availableLeagues.length === 0) {
  throw new Error('오늘 주요 리그 라이브/예정 경기가 없습니다. 가용 리그: ' +
    Object.entries(sportsData).map(([k,v]) => k + ':' + (v.count || 0)).join(', '));
}

// 랜덤 선택
const sel = availableLeagues[Math.floor(Math.random() * availableLeagues.length)];

// 경기 목록 표준화 (하류 호환 fixtures 형식)
const parsed = sel.matches.map(m => ({
  fixtureId: String(m.id),
  date: m.date,
  homeTeam: { id: String(m.home?.id || ''), name: m.home?.name || 'Home' },
  awayTeam: { id: String(m.away?.id || ''), name: m.away?.name || 'Away' },
  status: m.status?.short || m.status?.code || '',
  venue: m.venue || '',
  score: m.score || null
}));

// 순위 URL
let standingsUrl = '';
let useFdo = false;
if (sel.sport === 'soccer' && sel.fdoCode) {
  useFdo = true;
  standingsUrl = 'https://api.football-data.org/v4/competitions/' + sel.fdoCode + '/standings';
} else if (sel.sport === 'soccer' && sel.espnLeague) {
  standingsUrl = 'https://site.api.espn.com/apis/v2/sports/soccer/' + sel.espnLeague + '/standings';
} else if (sel.espnLeague) {
  const sportPath = sel.sport === 'basketball' ? 'basketball/nba' : 'baseball/mlb';
  standingsUrl = 'https://site.api.espn.com/apis/v2/sports/' + sportPath + '/standings';
}

// ODDS 매핑
const ODDS_MAP = {
  'soccer_epl': 'soccer_epl', 'soccer_spain_la_liga': 'soccer_spain_la_liga',
  'soccer_italy_serie_a': 'soccer_italy_serie_a', 'soccer_germany_bundesliga': 'soccer_germany_bundesliga',
  'soccer_france_ligue_one': 'soccer_france_ligue_one', 'soccer_korea_kleague1': 'soccer_korea_kleague1',
  'basketball_nba': 'basketball_nba', 'baseball_mlb': 'baseball_mlb'
};

return [{
  json: {
    // 종목 결정 보강 필드 (하류에서 $('경기 목록 파싱') 대신 여기서도 참조 가능)
    sport: sel.sport,
    league: { id: sel.scoredataLeagueId, name: sel.name, espnLeague: sel.espnLeague },
    standingsUrl,
    useFdo,
    oddsApiSport: sel.oddsSport,
    availableLeaguesSummary: availableLeagues.map(l => l.name + '(' + l.matchCount + ')').join(', '),
    // 경기 목록 (기존 하류 호환)
    fixtures: parsed,
    fixtureCount: parsed.length
  }
}];

// ESPN/TheSportsDB는 부상 API를 제공하지 않음
// 빈 결과 반환
return [{
  json: {
    response: [],
    available: false
  }
}];

// ESPN/TheSportsDB는 H2H API를 제공하지 않음
// 빈 결과 반환
return [{
  json: {
    response: [],
    available: false
  }
}];

// 순위 + 이전 픽 데이터 통합 (scoredata.org/football-data.org/ESPN)
const configData = $('종목 결정').first().json;
const fixtureData = $('경기 목록 파싱').first().json;
const standingsRaw = $('순위표 조회').first().json;
const injuriesData = $('부상자 조회').first().json;
const h2hData = $('상대전적 조회').first().json;

// fixtureData에서 sport/league/useFdo 가져옴 (scoredata.org 마이그레이션)
const sport = fixtureData.sport;
const league = fixtureData.league;
const useFdo = fixtureData.useFdo;

// 순위 파싱 (3가지 포맷 지원)
let standingsSummary = '';
try {
  if (useFdo && standingsRaw.standings) {
    // football-data.org 형식
    const table = standingsRaw.standings[0]?.table || [];
    standingsSummary = table.map(s => {
      return s.position + '위 ' + s.team.name + ' (' + s.points + '점, 폼:' + (s.form || '?') + ', ' + s.won + '승' + s.draw + '무' + s.lost + '패)';
    }).join('\n');
  } else if (configData.apiType === 'espn') {
    // ESPN 형식 (레거시 호환)
    const children = standingsRaw.children || [];
    if (children.length > 0) {
      const entries = children[0]?.standings?.entries || [];
      standingsSummary = entries.slice(0, 20).map((e, i) => {
        const stats = {};
        (e.stats || []).forEach(s => { stats[s.name] = s.value || s.displayValue; });
        return (i+1) + '위 ' + (e.team?.displayName || '?') + ' (' + (stats.points || stats.wins || '?') + '점, ' + (stats.gamesPlayed || stats.wins || '?') + '경기)';
      }).join('\n');
    } else {
      standingsSummary = '순위 데이터 없음';
    }
  } else {
    // ESPN REST 형식 (scoredata 기본)
    const children = standingsRaw.children || [];
    if (children.length > 0) {
      const entries = children[0]?.standings?.entries || [];
      standingsSummary = entries.slice(0, 20).map((e, i) => {
        const stats = {};
        (e.stats || []).forEach(s => { stats[s.name] = s.value || s.displayValue; });
        return (i+1) + '위 ' + (e.team?.displayName || '?') + ' (' + (stats.points || stats.wins || '?') + '점, ' + (stats.gamesPlayed || stats.wins || '?') + '경기)';
      }).join('\n');
    } else {
      standingsSummary = '순위 데이터 없음';
    }
  }
} catch(e) {
  standingsSummary = '순위 데이터 파싱 실패: ' + e.message;
}
if (!standingsSummary) standingsSummary = '순위 데이터 없음';


// 프로토 배당 데이터
let matchesFormatted = '';
let oddsAvailable = false;
try {
  const oddsData = $('배당 데이터 파싱').first().json;
  matchesFormatted = oddsData.matchesFormatted || '';
  oddsAvailable = oddsData.oddsAvailable || false;
} catch(e) { /* 배당 데이터 없으면 무시 */ }

// 부상자 (현재 미지원)
const injuriesSummary = injuriesData.available ? JSON.stringify(injuriesData.response).substring(0, 1000) : '부상 정보는 현재 API에서 제공하지 않습니다';

// H2H (현재 미지원)
const h2hSummary = h2hData.available ? JSON.stringify(h2hData.response).substring(0, 1000) : '상대전적 정보는 현재 API에서 제공하지 않습니다';

// 이전 픽 데이터
let prevPickResult = '미확인';
let prevMatchup = '';
let prevPick = '';
let isFirstPick = true;
try {
  const sheetData = $('이전 픽 조회').all();
  if (sheetData && sheetData.length > 0) {
    const lastRow = sheetData[sheetData.length - 1].json;
    prevPickResult = lastRow.pickResult || '미확인';
    prevMatchup = lastRow.matchup || '';
    prevPick = lastRow.pick || '';
    isFirstPick = false;
  }
} catch(e) { /* 첫 실행이거나 시트 비어있음 */ }

// 경기 목록 요약
const fixturesSummary = fixtureData.fixtures.map((f, i) => {
  return (i+1) + '. ' + f.homeTeam.name + ' vs ' + f.awayTeam.name + ' (ID: ' + f.fixtureId + ')';
}).join('\n');

return [{
  json: {
    sport,
    league,
    toneStyle: configData.toneStyle,
    toneGuide: configData.toneGuide,
    toneExamples: configData.toneExamples,
    fixtures: fixtureData.fixtures,
    fixturesSummary,
    standingsSummary,
    injuriesSummary,
    h2hSummary,
    prevPickResult,
    prevMatchup,
    prevPick,
    isFirstPick,
    today: configData.today,
    matchesFormatted,
    oddsAvailable,
    category: configData.category
  }
}];

values.content:
너는 스포츠 분석 전문가야. 아래 경기 목록과 데이터를 보고 가장 흥미로운 1경기를 선택해줘.

## 종목: {{ $json.sport }} / 리그: {{ $json.league.name }}

## 오늘 경기 목록
{{ $json.fixturesSummary }}

## 리그 순위표
{{ $json.standingsSummary }}

## 부상/결장 정보
{{ $json.injuriesSummary }}

## 상대전적
{{ $json.h2hSummary }}

## 선택 기준
- 순위 차이가 적절한 경기 (너무 일방적이지 않은)
- 최근 폼이 흥미로운 팀이 포함된 경기
- 분석 포인트가 많은 경기
- 반전 요소가 있을 수 있는 경기

## 출력 형식 (순수 JSON만, 코드블록 없이)
{ "selectedFixtureId": 경기ID, "homeTeam": "홈팀명", "awayTeam": "어웨이팀명", "reason": "선택 이유 한줄", "angle": "분석 각도 한줄", "hookIdea": "훅 아이디어 한줄" }

