// AI 경기 선택 결과 파싱
const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let data;
try {
  data = JSON.parse(cleanText);
} catch(e) {
  const first = cleanText.indexOf('{');
  const last = cleanText.lastIndexOf('}');
  if (first !== -1 && last > first) {
    data = JSON.parse(cleanText.substring(first, last + 1));
  } else {
    throw new Error('AI 경기 선택 JSON 파싱 실패: ' + cleanText.substring(0, 300));
  }
}

if (!data.selectedFixtureId) {
  throw new Error('selectedFixtureId가 없습니다: ' + JSON.stringify(data));
}

const mergedData = $('데이터 병합').first().json;

// 선택된 경기 찾기
const selectedFixture = mergedData.fixtures.find(f => String(f.fixtureId) === String(data.selectedFixtureId)) || mergedData.fixtures[0];

return [{
  json: {
    selectedFixtureId: data.selectedFixtureId,
    homeTeam: data.homeTeam || selectedFixture.homeTeam.name,
    awayTeam: data.awayTeam || selectedFixture.awayTeam.name,
    matchup: (data.homeTeam || selectedFixture.homeTeam.name) + ' vs ' + (data.awayTeam || selectedFixture.awayTeam.name),
    reason: data.reason || '',
    angle: data.angle || '',
    hookIdea: data.hookIdea || '',
    sport: mergedData.sport,
    league: mergedData.league,
    toneStyle: mergedData.toneStyle,
    toneGuide: mergedData.toneGuide,
    toneExamples: mergedData.toneExamples,
    standingsSummary: mergedData.standingsSummary,
    injuriesSummary: mergedData.injuriesSummary,
    h2hSummary: mergedData.h2hSummary,
    prevPickResult: mergedData.prevPickResult,
    prevMatchup: mergedData.prevMatchup,
    prevPick: mergedData.prevPick,
    isFirstPick: mergedData.isFirstPick,
    today: mergedData.today,
    matchesFormatted: mergedData.matchesFormatted || '',
    oddsAvailable: mergedData.oddsAvailable || false,
    category: 5
  }
}];

// 프로토 배당 데이터 파싱 (the-odds-api.com 응답 → matchesFormatted)
const raw = $input.first().json;

// the-odds-api 응답이 배열 형태
const events = Array.isArray(raw) ? raw : (raw.data || []);

if (!events || events.length === 0) {
  // 배당 데이터 없으면 빈 결과 반환 (카테고리 2~7에서는 무시됨)
  return [{
    json: {
      matchesFormatted: '배당 데이터 없음 (해당 리그의 프로토 배당이 없습니다)',
      oddsAvailable: false,
      oddsMatches: []
    }
  }];
}

// 경기별 배당 정리
const oddsMatches = events.slice(0, 10).map((ev, idx) => {
  const homeTeam = ev.home_team || '';
  const awayTeam = ev.away_team || '';
  const startTime = ev.commence_time || '';

  // 첫 번째 북메이커의 배당률 사용
  let homeOdds = '-';
  let drawOdds = '-';
  let awayOdds = '-';

  const bookmaker = (ev.bookmakers || [])[0];
  if (bookmaker) {
    const market = (bookmaker.markets || []).find(m => m.key === 'h2h');
    if (market) {
      for (const outcome of (market.outcomes || [])) {
        if (outcome.name === homeTeam) homeOdds = outcome.price;
        else if (outcome.name === awayTeam) awayOdds = outcome.price;
        else if (outcome.name === 'Draw') drawOdds = outcome.price;
      }
    }
  }

  return {
    index: idx + 1,
    homeTeam,
    awayTeam,
    homeOdds,
    drawOdds,
    awayOdds,
    startTime
  };
});

// matchesFormatted 문자열 생성 (프롬프트에 주입)
const matchesFormatted = oddsMatches.map(m => {
  const drawPart = m.drawOdds !== '-' ? ` / 무 ${m.drawOdds}` : '';
  return `${m.index}. ${m.homeTeam} vs ${m.awayTeam} — 승 ${m.homeOdds}${drawPart} / 패 ${m.awayOdds}`;
}).join('\n');

return [{
  json: {
    matchesFormatted,
    oddsAvailable: true,
    oddsMatches,
    oddsSource: 'the-odds-api',
    oddsCount: oddsMatches.length
  }
}];

/**
 * v1.2 프롬프트 조립
 * - 경기 선택 파싱 결과 + 카테고리 데이터를 Gemini user message로 조립
 * - 시스템 프롬프트(v1.2)는 별도 반환하여 Gemini 노드에서 system message로 사용
 */
const data = $input.first().json;
const category = data.category || 2;

// 이전 픽 가이드 (category 2에서 활용)
let prevPickGuide = '';
if (data.isFirstPick) {
  prevPickGuide = '이번이 첫 번째 픽입니다.';
} else if (data.prevPickResult === '적중') {
  prevPickGuide = '지난 픽 "' + (data.prevMatchup || '') + ' → ' + (data.prevPick || '') + '" 적중! 자신감 있게 언급하세요.';
} else if (data.prevPickResult === '실패') {
  prevPickGuide = '지난 픽 "' + (data.prevMatchup || '') + ' → ' + (data.prevPick || '') + '" 실패. 솔직하게 인정하고 오늘은 다르다고 하세요.';
} else {
  prevPickGuide = '이전 픽 결과 미확인.';
}

// user message 조립
const parts = [
  '## 입력 데이터',
  'category_id: ' + category,
  '종목: ' + (data.sport || ''),
  '리그: ' + (data.league?.name || data.league || ''),
  '날짜: ' + (data.today || ''),
];

if (data.matchup) {
  parts.push('대진: ' + data.matchup);
  parts.push('홈: ' + (data.homeTeam || '') + ' / 어웨이: ' + (data.awayTeam || ''));
}
if (data.angle) parts.push('분석 각도: ' + data.angle);
if (data.hookIdea) parts.push('훅 아이디어: ' + data.hookIdea);

parts.push('');
parts.push('## 리그 순위');
parts.push(data.standingsSummary || '데이터 없음');

if (data.oddsAvailable && data.matchesFormatted) {
  parts.push('');
  parts.push('## 프로토 배당 데이터');
  parts.push(data.matchesFormatted);
}

parts.push('');
parts.push('## 부상/결장 정보');
parts.push(data.injuriesSummary || '데이터 없음');

parts.push('');
parts.push('## 상대전적');
parts.push(data.h2hSummary || '데이터 없음');

if (category === 2) {
  parts.push('');
  parts.push('## 이전 픽 결과');
  parts.push(prevPickGuide);
}

// 톤 스타일 (v1에서 이미 선택된 것 전달)
if (data.toneStyle) {
  parts.push('');
  parts.push('## 톤 스타일 지정: ' + data.toneStyle);
  if (data.toneGuide) parts.push(data.toneGuide);
}

