const tid = script.template_id;
const tplStr = TEMPLATES[tid];
if (!tplStr) throw new Error('지원하지 않는 template_id: ' + tid);

let tpl = JSON.parse(tplStr);

// 플레이스홀더 치환 함수
function replacePlaceholders(obj, map) {
  const str = JSON.stringify(obj);
  let result = str;
  for (const [key, val] of Object.entries(map)) {
    const placeholder = '{{' + key + '}}';
    result = result.split(placeholder).join(String(val));
  }
  return JSON.parse(result);
}

// 공통 플레이스홀더 (3-segment narration)
const commonMap = {
  narr_intro: narrIntro,
  narr_body: narrBody,
  narr_outro: narrOutro,
  bgm_audio: bgmUrl,
  duration_sec: durationSec.toFixed(2),
  fontfile: fontfile,
  cta_text: ctaText,
  bgm_volume: bgmVolume,
  fade_out_start: fadeOutStart.toFixed(2),
  output_filename: outputFilename
};

// 템플릿별 추가 플레이스홀더
let templateMap = {};

if (tid === 'A') {
  templateMap = {
    bg: caps[0]?.url || caps[caps.length - 1]?.url || '',
    team_a_card: caps[1]?.url || caps[0]?.url || '',
    team_b_card: caps[2]?.url || caps[1]?.url || caps[0]?.url || '',
    vs_stats: caps[3]?.url || caps[2]?.url || caps[0]?.url || '',
    hook_text: hookText,
    key_point_text: keyPointText,
    conclusion_text: conclusionText,
    reveal_t: (durationSec * 0.7).toFixed(2)
  };
} else if (tid === 'B') {
  const tbParams = timelineData.template_b_params || {};
  const vp = script.visual_plan?.template_b || {};
  templateMap = {
    long_capture: caps[0]?.url || '',
    overlay_x: vp.overlay_x ?? 0,
    overlay_y_start: vp.overlay_y_start ?? 400,
    HOLD: tbParams.HOLD?.toFixed(3) || vp.hold_sec || '1.000',
    SCROLL: tbParams.SCROLL?.toFixed(3) || vp.scroll_sec_min || '6.000'
  };
} else if (tid === 'C') {
  templateMap = {
    bg: caps[0]?.url || '',
    scoreboard: caps[1]?.url || caps[0]?.url || '',
    frame_overlay: caps[2]?.url || caps[1]?.url || caps[0]?.url || '',
    headline_text: hookText || keyPointText,
    ticker_text: conclusionText || keyPointText || hookText,
    ticker_px_per_sec: '150'
  };
}

const fullMap = { ...commonMap, ...templateMap };
const nca_payload = replacePlaceholders(tpl, fullMap);

// _comment 제거
delete nca_payload._comment;

return [{
  json: {
    nca_payload,
    template_id: tid,
    totalDuration: durationSec,
    captureCount: caps.length,
    subject: script.hook_text || '',
    caption: script.cta_text || '',
    comment: '라이브365에서 더 많은 정보 확인!',
    category: scriptData.category,
    matchup: scriptData.matchup || ''
  }
}];

/**
 * NCA 결과 처리
 * - NCA 서버 응답에서 영상 URL 추출
 */
const result = $input.first().json;
const prevData = $('NCA 데이터 준비 v2').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
  videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
  videoUrl = result.response;
} else {
  videoUrl = result.output_url || result.url || result.video_url || result.file_url || '';
}

if (!videoUrl) {
  throw new Error('NCA 영상 제작 결과 URL 없음: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    '영상 URL': videoUrl,
    Status: '완료',
    matchup: prevData.matchup || '',
    category: prevData.category,
    template_id: prevData.template_id
  }
}];
